sql:
SELECT agent_id, COUNT(*) AS assignment_count
FROM service_request_assignments
GROUP BY agent_id;

SELECT description
   FROM service_times
   WHERE service_time_fix < 30;

SELECT status
   FROM service_windows
   WHERE status IN ('scheduled', 'in-progress');

SELECT assignment_id, request_id, assignment_status
FROM service_request_assignments
WHERE assignment_status = 'assigned';

SELECT status, COUNT(*) AS status_count
FROM service_windows
GROUP BY status;

external_knowledge:
; in-progress service requests refer to those that have begun but not yet completed; 
; a service window is a scheduled time period for service; 
; the rank of an assignment refers to its order in the sequence of assignments for a given service request.
